private void injectMockCandidate(Class<?> awaitingInjectionClazz, Set<Object> mocks, Object fieldInstance) {
    for(Field field : orderedInstanceFieldsFrom(awaitingInjectionClazz)) {
        if (field == null || fieldInstance == null) {
            continue; // Skip null fields or field instances
        }
        Object selectedMock = mockCandidateFilter.filterCandidate(mocks, field, fieldInstance);
        if (selectedMock != null) {
            try {
                field.setAccessible(true);
                if (!field.getType().isAssignableFrom(selectedMock.getClass())) {
                    throw new IllegalArgumentException("Incompatible type for field " + field.getName() + ". Expected: " + field.getType().getName() + ", Found: " + selectedMock.getClass().getName());
                }
                field.set(fieldInstance, selectedMock);
            } catch (IllegalAccessException e) {
                throw new RuntimeException("Failed to inject mock into field " + field.getName(), e);
            }
        }
    }
}
